import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * MANIFEST - an order manifest over a group OCCURS table, translated from
 * COBOL 85. Faithful variant: exact COBOL behavior over Java idiom.
 *
 * W-ITEM OCCURS 3 groups four leaves (sku, unit price, quantity in
 * tenths, extension); with every access leaf-wise the group table is
 * semantically parallel per-leaf tables, so the translation carries one
 * 1-based array per leaf. Each row's extension is qty * price ROUNDED to
 * the cent, and the BIG tier splits on the total of the three cells.
 */
public final class Manifest {

    /** PIC 9(3)V9 capacity (W-QTY). */
    private static final BigDecimal PIC_9_3_V9 = new BigDecimal("1000");
    /** PIC 9(6)V99 capacity (W-EXT). */
    private static final BigDecimal PIC_9_6_V99 = new BigDecimal("1000000");
    /** PIC 9(7)V99 capacity (W-TOTAL). */
    private static final BigDecimal PIC_9_7_V99 = new BigDecimal("10000000");
    /** IF W-TOTAL > 100. */
    private static final BigDecimal THRESHOLD = new BigDecimal("100");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        // W-ITEM OCCURS 3: parallel per-leaf tables, 1-based (index 0 unused).
        String[] sku = new String[4];
        sku[1] = "PLNK";
        sku[2] = "BOLT";
        sku[3] = "GEAR";

        BigDecimal[] price = new BigDecimal[4];
        price[1] = new BigDecimal("2.35");
